  `notes` text COLLATE utf8mb4_unicode_ci,
  `submitted_at` timestamp NULL DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `service_requests_reference_number_unique` (`reference_number`),
  KEY `service_requests_citizen_id_foreign` (`citizen_id`),
  KEY `service_requests_service_id_foreign` (`service_id`),
  KEY `service_requests_office_id_foreign` (`office_id`),
